## Step 2: The fully deobfuscated code

```javascript
// ─── Constants ─────────────────────────────────────────────
var TAU = 6.283;           // ≈ 2π (full circle in radians)
var PHI = 1.618;           // ≈ golden ratio
var SQRT1_2 = 0.707;       // ≈ 1/√2 ≈ √2/2

// ─── Physics / Simulation Parameters ──────────────────────
var params = {
  attraction:      4000,    // repulsion numerator between all node pairs
  springCoeff:     0.004,   // default spring stiffness on edges
  amplification:   0.92,    // velocity damping factor each tick
  centerPull:      0.0003,  // strength pulling every node toward center
  streamSize:      40,      // max number of particles alive at once
  streamDecay:     0.04,    // particle drag / decay factor
  theta:           0.06     // camera interpolation (smoothing) factor
};

// ─── Nodes ─────────────────────────────────────────────────
var nodes = [
  { id: "hub",     label: "Nexus",   r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// ─── Edges (springs) ───────────────────────────────────────
var edges = [
  { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub", b: "beta",    rest: 160, k: 0.005 },
  { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub", b: "delta",   rest: 170, k: 0.004 },
  { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha",b: "beta",   rest: 200, k: 0.002 },
  { a: "gamma",b: "delta",  rest: 220, k: 0.002 },
  { a: "alpha",b: "epsilon",rest: 200, k: 0.002 }
];

// ─── Camera ────────────────────────────────────────────────
var camera       = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// ─── Particles & Frame Counter ─────────────────────────────
var particles = [];
var frameCount = 0;

// ─── Helper: find node by id ──────────────────────────────
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// ─── Physics step ──────────────────────────────────────────
function physicsStep() {

  // 1) Node–node repulsion (Coulomb-like)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx   = nodes[i].x - nodes[j].x;
      var dy   = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = params.attraction / (dist * dist);   // inverse-square repulsion
      var fx   = (dx / dist) * force;
      var fy   = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Edge spring forces (Hooke-like)
  for (var e = 0; e < edges.length; e++) {
    var nA = findNode(edges[e].a);
    var nB = findNode(edges[e].b);
    if (!nA || !nB) continue;
    var dx    = nB.x - nA.x;
    var dy    = nB.y - nA.y;
    var dist  = Math.sqrt(dx * dx + dy * dy) || 1;
    var stretch = dist - edges[e].rest;
    var force = (edges[e].k || params.springCoeff) * stretch;
    nA.vx += (dx / dist) * force;
    nA.vy += (dy / dist) * force;
    nB.vx -= (dx / dist) * force;
    nB.vy -= (dy / dist) * force;
  }

  // 3) Per-node: center pull → damping → integrate position
  for (var n = 0; n < nodes.length; n++) {
    // center pull toward (400, 300)
    nodes[n].vx += (400 - nodes[n].x) * params.centerPull;
    nodes[n].vy += (300 - nodes[n].y) * params.centerPull;
    // velocity damping
    nodes[n].vx *= params.amplification;
    nodes[n].vy *= params.amplification;
    // integrate
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// ─── Spawn a particle ──────────────────────────────────────
function spawnParticle() {
  if (particles.length >= params.streamSize) return;
  var source = nodes[Math.floor(Math.random() * nodes.length)];
  var angle  = Math.random() * TAU;
  var speed  = 0.3 + Math.random() * SQRT1_2;
  particles.push({
    x:      source.x,
    y:      source.y,
    vx:     Math.cos(angle) * speed,
    vy:     Math.sin(angle) * speed,
    age:    0,
    maxAge: 800 + Math.random() * 1200,
    size:   0.8 + (Math.random() * PHI) * SQRT1_2
  });
}

// ─── Update particles ──────────────────────────────────────
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    p.age++;
    // remove dead particles
    if (p.age > p.maxAge) {
      particles.splice(i, 1);
      continue;
    }
    // drag / decay
    p.vx *= 1 - params.streamDecay * 0.125;
    p.vy *= 1 - params.streamDecay * 0.125;
    // integrate
    p.x += p.vx;
    p.y += p.vy;
  }
}

// ─── Smooth camera follow ──────────────────────────────────
function updateCamera() {
  camera.x    += (cameraTarget.x    - camera.x)    * params.theta;
  camera.y    += (cameraTarget.y    - camera.y)    * params.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom)  * params.theta;
}

// ─── Main tick ─────────────────────────────────────────────
function tick() {
  physicsStep();
  updateParticles();
  updateCamera();
  if (frameCount % 3 === 0) spawnParticle();
  frameCount++;
}

setInterval(tick, 16);   // ≈ 60 fps
```

